// Select random topic and content type for variety
const topics = [
  { category: 'Product Launch', focus: 'announcing new features', tone: 'excited' },
  { category: 'Industry Insights', focus: 'latest trends and analysis', tone: 'professional' },
  { category: 'Customer Success', focus: 'testimonials and case studies', tone: 'inspiring' },
  { category: 'Tips & How-To', focus: 'practical advice and tutorials', tone: 'helpful' },
  { category: 'Company Culture', focus: 'behind-the-scenes and team highlights', tone: 'friendly' },
  { category: 'Thought Leadership', focus: 'industry opinions and insights', tone: 'authoritative' },
  { category: 'Events & Webinars', focus: 'upcoming events and recordings', tone: 'inviting' },
  { category: 'Industry News', focus: 'recent developments and commentary', tone: 'informative' }
];

const contentTypes = ['Educational', 'Promotional', 'Engagement', 'Storytelling'];

// Select random topic
const selectedTopic = topics[Math.floor(Math.random() * topics.length)];
const selectedType = contentTypes[Math.floor(Math.random() * contentTypes.length)];

const timestamp = new Date().toISOString();
const dateString = new Date().toLocaleDateString('en-US', { 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric' 
});

// Generate unique post ID
const postId = `POST-${new Date().getFullYear()}-${String(new Date().getMonth() + 1).padStart(2, '0')}-${String(new Date().getDate()).padStart(2, '0')}-${Math.floor(Math.random() * 10000)}`;

return [
  {
    json: {
      postId,
      timestamp,
      dateString,
      topic: selectedTopic,
      contentType: selectedType,
      category: selectedTopic.category,
      focus: selectedTopic.focus,
      tone: selectedTopic.tone
    }
  }
];

// Extract generated content from OpenAI response
const data = $input.item.json;
const inputData = $input.first().json;

const aiContent = data.choices?.[0]?.message?.content || 'Failed to generate content';

// Parse the generated content
const lines = aiContent.split('\n').filter(line => line.trim());
const baseContent = aiContent;

// Extract hashtags if present
const hashtagRegex = /#\w+/g;
const hashtags = aiContent.match(hashtagRegex) || [];

// Remove hashtags from base content for cleaner text
const contentWithoutHashtags = aiContent.replace(hashtagRegex, '').trim();

return {
  json: {
    ...inputData,
    aiGeneratedContent: baseContent,
    contentWithoutHashtags,
    extractedHashtags: hashtags,
    wordCount: baseContent.split(/\s+/).length,
    hasHashtags: hashtags.length > 0
  }
};

// Create platform-specific versions of the content
const data = $input.item.json;
const baseContent = data.contentWithoutHashtags;
const hashtags = data.extractedHashtags || [];

// --- LINKEDIN VERSION ---
// LinkedIn allows 3000 chars but optimal is 150-250 words
// Professional tone, less emojis
let linkedinContent = baseContent;
if (linkedinContent.length > 1200) {
  linkedinContent = linkedinContent.substring(0, 1200) + '...';
}
linkedinContent += '\n\n' + hashtags.slice(0, 5).join(' ');

// --- TWITTER/X VERSION ---
// Twitter has 280 character limit
// Need to be concise, use more hashtags
let twitterContent = baseContent;
if (twitterContent.length > 220) {
  // Find first sentence or cut at 220 chars
  const firstSentence = twitterContent.match(/^[^.!?]+[.!?]/);
  if (firstSentence && firstSentence[0].length < 220) {
    twitterContent = firstSentence[0];
  } else {
    twitterContent = twitterContent.substring(0, 220) + '...';
  }
}
// Add hashtags (leave room for them)
const hashtagString = hashtags.slice(0, 3).join(' ');
if (twitterContent.length + hashtagString.length + 3 <= 280) {
  twitterContent += '\n\n' + hashtagString;
}

// --- FACEBOOK VERSION ---
// Facebook optimal is 40-80 characters for max engagement
// But can be longer (63,206 limit). We'll go for ~300 words max
let facebookContent = baseContent;
if (facebookContent.length > 1500) {
  facebookContent = facebookContent.substring(0, 1500) + '...';
}
// Facebook uses hashtags but they're less important
facebookContent += '\n\n' + hashtags.slice(0, 5).join(' ');

// Add emoji enhancement for Facebook (more casual)
const emojiMap = {
  'excited': '🚀 ',
  'professional': '💼 ',
  'inspiring': '⭐ ',
  'helpful': '💡 ',
  'friendly': '😊 ',
  'authoritative': '🎯 ',
  'inviting': '🎉 ',
  'informative': '📊 '
};

const emoji = emojiMap[data.tone] || '✨ ';
facebookContent = emoji + facebookContent;

return {
  json: {
    ...data,
    platforms: {
      linkedin: {
        content: linkedinContent,
        platform: 'LinkedIn',
        characterCount: linkedinContent.length,
        hashtagCount: hashtags.slice(0, 5).length
      },
      twitter: {
        content: twitterContent,
        platform: 'Twitter/X',
        characterCount: twitterContent.length,
        hashtagCount: hashtags.slice(0, 3).length,
        withinLimit: twitterContent.length <= 280
      },
      facebook: {
        content: facebookContent,
        platform: 'Facebook',
        characterCount: facebookContent.length,
        hashtagCount: hashtags.slice(0, 5).length,
        hasEmoji: true
      }
    },
    totalHashtags: hashtags.length,
    platformCount: 3
  }
};

// Prepare consolidated record for database storage
const items = $input.all();
const firstItem = items[0].json;

const timestamp = new Date().toISOString();

// Extract platform results
const platformResults = {};
const postLinks = {};

items.forEach(item => {
  const platform = item.json.platform;
  const responseData = item.json;

  platformResults[platform] = {
    success: responseData.id || responseData.data?.id ? true : false,
    postId: responseData.id || responseData.data?.id || null,
    characterCount: item.json.characterCount || 0
  };

  // Build post links (platform-specific)
  if (platform === 'LinkedIn' && responseData.id) {
    postLinks[platform] = `https://www.linkedin.com/feed/update/${responseData.id}`;
  } else if (platform === 'Twitter/X' && responseData.data?.id) {
    postLinks[platform] = `https://twitter.com/user/status/${responseData.data.id}`;
  } else if (platform === 'Facebook' && responseData.id) {
    postLinks[platform] = `https://www.facebook.com/${responseData.id}`;
  }
});

const allSuccessful = Object.values(platformResults).every(r => r.success);
const successCount = Object.values(platformResults).filter(r => r.success).length;

return [
  {
    json: {
      postId: firstItem.postId,
      timestamp,
      category: firstItem.category,
      contentType: firstItem.contentType,
      tone: firstItem.tone,
      focus: firstItem.focus,
      baseContent: firstItem.aiGeneratedContent,
      linkedinContent: firstItem.platforms?.linkedin?.content || '',
      twitterContent: firstItem.platforms?.twitter?.content || '',
      facebookContent: firstItem.platforms?.facebook?.content || '',
      totalHashtags: firstItem.totalHashtags || 0,
      wordCount: firstItem.wordCount || 0,
      platformResults: JSON.stringify(platformResults),
      postLinks: JSON.stringify(postLinks),
      allPlatformsSuccess: allSuccessful,
      successfulPlatforms: successCount,
      status: allSuccessful ? 'PUBLISHED' : 'PARTIAL',
      publishedAt: timestamp
    }
  }
];

// Create formatted Slack notification message
const data = $input.item.json;

const statusEmoji = data.allPlatformsSuccess ? '✅' : '⚠️';
const statusText = data.allPlatformsSuccess ? 'Successfully Published' : 'Partially Published';

const postLinks = JSON.parse(data.postLinks || '{}');

let linkSection = '';
for (const [platform, link] of Object.entries(postLinks)) {
  linkSection += `\n• *${platform}:* <${link}|View Post>`;
}

if (!linkSection) {
  linkSection = '\n_No post links available_';
}

const message = `${statusEmoji} *Social Media Post ${statusText}*\n\n` +
  `*Post ID:* ${data.postId}\n` +
  `*Category:* ${data.category}\n` +
  `*Content Type:* ${data.contentType}\n` +
  `*Tone:* ${data.tone}\n` +
  `*Platforms:* ${data.successfulPlatforms}/3 successful\n` +
  `*Hashtags Used:* ${data.totalHashtags}\n` +
  `*Word Count:* ${data.wordCount}\n\n` +
  `*Post Links:*${linkSection}\n\n` +
  `*Preview:*\n_${data.baseContent.substring(0, 150)}${data.baseContent.length > 150 ? '...' : ''}_`;

return {
  json: {
    ...data,
    slackMessage: message,
    slackTitle: `${statusEmoji} Social Media Post ${statusText}`
  }
};

// Log successful execution and track statistics
const data = $input.item.json;
const timestamp = new Date().toISOString();

console.log(`✅ SUCCESS: Social post ${data.postId} | Status: ${data.status} | Platforms: ${data.successfulPlatforms}/3 | Category: ${data.category} | Time: ${timestamp}`);

// Update cumulative statistics
const stats = $getWorkflowStaticData('global').socialStats || {
  totalPosts: 0,
  successfulPosts: 0,
  partialPosts: 0,
  failedPosts: 0,
  totalHashtags: 0,
  platformBreakdown: {
    linkedin: 0,
    twitter: 0,
    facebook: 0
  },
  categoryBreakdown: {},
  lastPosted: null
};

stats.totalPosts++;
if (data.status === 'PUBLISHED') stats.successfulPosts++;
else if (data.status === 'PARTIAL') stats.partialPosts++;
else stats.failedPosts++;

stats.totalHashtags += data.totalHashtags || 0;
stats.lastPosted = timestamp;

// Update category stats
if (!stats.categoryBreakdown[data.category]) {
  stats.categoryBreakdown[data.category] = 0;
}
stats.categoryBreakdown[data.category]++;

// Update platform stats from results
const platformResults = JSON.parse(data.platformResults || '{}');
for (const [platform, result] of Object.entries(platformResults)) {
  if (result.success) {
    const platformKey = platform.toLowerCase().replace(/\/x$/, '');
    if (stats.platformBreakdown[platformKey] !== undefined) {
      stats.platformBreakdown[platformKey]++;
    }
  }
}

$getWorkflowStaticData('global').socialStats = stats;

return {
  json: {
    success: true,
    postId: data.postId,
    status: data.status,
    platformsPublished: data.successfulPlatforms,
    category: data.category,
    timestamp,
    cumulativeStats: stats
  }
};
